input.command:
./cli/bin/ctl list orders --limit 1000 --format json | python3 -c "
import sys, json
post = json.load(sys.stdin)
with open('/tmp/pre_deploy_orders.json') as f:
    pre = json.load(f)
if pre == post:
    print('Orders: IDENTICAL (no mutations)')
else:
    print('Orders: CHANGED')
    for i, (a, b) in enumerate(zip(pre, post)):
        if a != b:
            print(f'  Diff at index {i}: {a[\"id\"]} -> {b[\"id\"]}')
"

